import React, { useEffect, useRef, useCallback, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import styled from 'styled-components';
import { useTranslation } from 'react-i18next';

// Components
import ProductCard from '../components/ProductCard';
import Loading from '../components/Loading';
import Error from '../components/Error';

// API
import { getStoreDiscounts } from '../utils/api';

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 1.5rem;

  @media (max-width: 480px) {
    padding: 1rem 0.75rem;
  }
`;

const BackLink = styled(Link)`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  color: ${({ theme }) => theme.colors.primary};
  font-weight: 500;
  margin-bottom: 1rem;

  &:hover {
    text-decoration: underline;
  }

  @media (max-width: 480px) {
    font-size: 0.9rem;
    margin-bottom: 0.75rem;
  }
`;

const StoreHeader = styled.div`
  margin-bottom: 2rem;
  display: flex;
  flex-direction: column;

  @media (max-width: 480px) {
    margin-bottom: 1.25rem;
  }
`;

const StoreNameRow = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.5rem;

  @media (max-width: 768px) {
    flex-direction: column;
    align-items: flex-start;
    gap: 0.75rem;
  }
`;

const StoreName = styled.h1`
  font-size: ${({ theme }) => theme.fontSizes['2xl']};
  font-weight: 700;
  color: ${({ theme }) => theme.colors.text};
  margin: 0;

  @media (max-width: 480px) {
    font-size: 1.5rem;
  }
`;

const StoreLocation = styled.p`
  font-size: ${({ theme }) => theme.fontSizes.md};
  color: ${({ theme }) => theme.colors.textLight};
  text-align: right;

  @media (max-width: 480px) {
    font-size: 0.9rem;
  }
`;

const SearchContainer = styled.div`
  position: relative;
  width: 300px;

  @media (max-width: 768px) {
    width: 100%;
  }
`;

const SearchInput = styled.input`
  width: 100%;
  padding: 0.5rem 2rem 0.5rem 0.75rem;
  border: 1px solid ${({ theme }) => theme.colors.border};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  font-size: ${({ theme }) => theme.fontSizes.md};

  &:focus {
    outline: none;
    border-color: ${({ theme }) => theme.colors.primary};
    box-shadow: 0 0 0 2px ${({ theme }) => theme.colors.primary}33;
  }

  @media (max-width: 480px) {
    font-size: 0.9rem;
    padding: 0.4rem 2rem 0.4rem 0.75rem;
  }
`;

const SearchIcon = styled.span`
  position: absolute;
  right: 0.75rem;
  top: 50%;
  transform: translateY(-50%);
  color: ${({ theme }) => theme.colors.textLight};
  pointer-events: none;
`;

const CategorySliderContainer = styled.div`
  margin: 1.5rem 0;
  display: grid;
  grid-auto-flow: column; /* Элементы в один ряд */
  gap: 0.01px;
  overflow-x: auto; /* Горизонтальный скроллинг */
  scrollbar-width: none; /* Скрыть ползунок в Firefox */
  -ms-overflow-style: none; /* Скрыть ползунок в IE/Edge */
  padding-bottom: 0.5rem;

  &::-webkit-scrollbar {
    display: none; /* Скрыть ползунок в Chrome, Safari и других Webkit-браузерах */
  }

  @media (max-width: 480px) {
    margin: 1rem 0;
  }
`;

const CategoryItem = styled.div`
  padding: 0.5rem 1rem;
  margin: 0 0.5rem;
  background-color: ${({ active, theme }) => active ? theme.colors.primary : '#4F4F4F'};
  color: ${({ active, theme }) => active ? 'white' : theme.colors.text};
  border-radius: ${({ theme }) => theme.borderRadius.md};
  cursor: pointer;
  text-align: center;
  transition: all 0.2s ease;
  white-space: nowrap;
  font-size: 0.9rem;

  &:hover {
    background-color: ${({ active, theme }) => active ? theme.colors.primary : '#e0e0e0'};
  }

  @media (max-width: 480px) {
    padding: 0.4rem 0.75rem;
    margin: 0 0.3rem;
    font-size: 0.8rem;
  }
`;

const SectionTitle = styled.h2`
  font-size: ${({ theme }) => theme.fontSizes.xl};
  font-weight: 600;
  margin-bottom: 1.5rem;
  color: ${({ theme }) => theme.colors.text};

  @media (max-width: 480px) {
    font-size: 1.25rem;
    margin-bottom: 1rem;
  }
`;

const Grid = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1.5rem;

  @media (max-width: 768px) {
    grid-template-columns: repeat(2, 1fr);
    gap: 1rem;
  }

  @media (max-width: 480px) {
    grid-template-columns: repeat(2, 1fr);
    gap: 0.75rem;
  }
`;

const EmptyState = styled.div`
  text-align: center;
  padding: 3rem 1rem;
  color: ${({ theme }) => theme.colors.textLight};

  @media (max-width: 480px) {
    padding: 2rem 0.5rem;
    font-size: 0.9rem;
  }
`;

const StoreDetail = () => {
  const { storeId } = useParams();
  const { t } = useTranslation();
  const [loading, setLoading] = React.useState(true);
  const [error, setError] = React.useState(null);
  const [data, setData] = React.useState(null);
  const [searchTerm, setSearchTerm] = React.useState('');
  const [categories, setCategories] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('');
  const fetchingRef = useRef(false);
  const categoriesFetchingRef = useRef(false);

  const fetchData = useCallback(async () => {
    if (fetchingRef.current) return;

    try {
      setLoading(true);
      setError(null);
      fetchingRef.current = true;

      console.log(`Fetching store discounts for ID: ${storeId}`);
      const result = await getStoreDiscounts(storeId);
      console.log('Store discounts result:', result);

      setData(result);
      setLoading(false);
    } catch (err) {
      console.error('Error fetching store discounts:', err);
      setError(err);
      setLoading(false);
    } finally {
      fetchingRef.current = false;
    }
  }, [storeId]);

  // Fetch categories for the store
  const fetchCategories = useCallback(async () => {
    if (categoriesFetchingRef.current || !storeId) return;

    try {
      categoriesFetchingRef.current = true;
      const response = await fetch(`/api/store/${storeId}/categories`);
      if (!response.ok) {
        throw new Error('Failed to fetch categories');
      }
      const data = await response.json();
      setCategories(data);
    } catch (err) {
      console.error('Error fetching categories:', err);
    } finally {
      categoriesFetchingRef.current = false;
    }
  }, [storeId]);

  useEffect(() => {
    fetchData();

    // Очищаем состояние при размонтировании
    return () => {
      fetchingRef.current = false;
    };
  }, [fetchData, storeId]);

  useEffect(() => {
    if (storeId) {
      fetchCategories();
    }

    return () => {
      categoriesFetchingRef.current = false;
    };
  }, [fetchCategories, storeId]);

  const store = data?.store;
  const discounts = data?.discounts || [];

  // Filter discounts based on search term and selected category
  const filteredDiscounts = discounts.filter(product => {
    const matchesSearch = searchTerm
      ? product.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        product.category.toLowerCase().includes(searchTerm.toLowerCase())
      : true;

    const matchesCategory = selectedCategory
      ? product.category === selectedCategory
      : true;

    return matchesSearch && matchesCategory;
  });

  return (
    <Container>
      <BackLink to="/">
        ← {t('backToStores')}
      </BackLink>

      {loading ? (
        <Loading />
      ) : error ? (
        <Error onRetry={() => fetchData()} />
      ) : store ? (
        <>
          <StoreHeader>
            <StoreNameRow>
              <StoreName>{store.name}</StoreName>
              <SearchContainer>
                <SearchInput 
                  type="text" 
                  placeholder={t('searchProducts')}
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
                <SearchIcon>🔍</SearchIcon>
              </SearchContainer>
            </StoreNameRow>
            <StoreLocation>{store.city.charAt(0).toUpperCase() + store.city.slice(1)}</StoreLocation>
          </StoreHeader>

          {categories.length > 0 && (
            <CategorySliderContainer>
              <CategoryItem active={selectedCategory === ''} onClick={() => setSelectedCategory('')}>
                {t('allCategories')}
              </CategoryItem>
              {categories.map((category, index) => (
                <CategoryItem
                  key={index}
                  active={selectedCategory === category}
                  onClick={() => setSelectedCategory(category)}
                >
                  {category}
                </CategoryItem>
              ))}
            </CategorySliderContainer>
          )}

          <SectionTitle>{t('discountedProducts')}</SectionTitle>

          {filteredDiscounts.length > 0 ? (
            <Grid>
              {filteredDiscounts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  store={store}
                />
              ))}
            </Grid>
          ) : (
            <EmptyState>
              <p>{searchTerm || selectedCategory ? t('noSearchResults') : t('noDiscounts')}</p>
            </EmptyState>
          )}
        </>
      ) : (
        <EmptyState>
          <p>{t('storeNotFound')}</p>
        </EmptyState>
      )}
    </Container>
  );
};

export default StoreDetail;
